data.solution:
guesses = [int(input()) for _ in range(int(input()))]
in_game, prev_guess = False, None
inputs = int(input())
for i in range(inputs + 1):
    user = input() if i < inputs else "_"
    if not in_game:
        in_game = user == "start"
        print("$", user)
        continue
    elif prev_guess is None: print("  Pick 1-20:", user)
    elif prev_guess > guesses[0]: print("  Lower:", user)
    else: print("  Higher:", user)
    try:
        prev_guess = int(user)
        if not 1 <= prev_guess <= 20: raise ValueError
    except ValueError: prev_guess = None
    if prev_guess == guesses[0]:
        print("  Correct!")
        in_game, prev_guess = False, None
        _ = guesses.pop(0)
